// **********************************************************
// @description Decorate Input Content with eNeX™
//
// @param   {object} data - payload
// @param   {object} $    - {tenant, id, action}
// @param   {object} ctx  - opentracing context
// @param   {object} this - ARES
//
// @return  {object} data - payload decorated
// **********************************************************

if (data.superkeywords) return data;

const url = `https://test.be.ares-mediaset.net/api/ares-rti-entities-extractor/extract?tenant=${$.tenant}`;
const fields = ["title", "description"];
const body = [];

for (const field of fields) {
  if (data[field]) {
    body.push(data[field]);
  }
}

const res = await fetch(url, {
  method: "POST",
  headers: {
    "Content-Type": "application/json"
  },
  body: JSON.stringify(body.join(" "))
});

const keys = await res.json();

if (keys?.all) {
  data.superkeywords = keys.all;
}
return data;
